    """Evaluate all filters against a single search result."""
    for field_name, filter_spec in filters.items():
        if not _evaluate_field_filter(result, field_name, filter_spec):
            return False
    return True

def _evaluate_field_filter(result: SearchResult, field_name: str, filter_spec: Dict[str, Any]) -> bool:
    """Evaluate a single field filter against a search result."""
    # First check metadata, then check passage metadata if not found in top-level
    field_value = result.metadata.get(field_name)
    if field_value is None:
        # Try to get from passage metadata (if available)
        passage_id = result.id
        if hasattr(result, 'metadata') and 'passage_metadata' in result.metadata:
            passage_meta = result.metadata['passage_metadata']
            if passage_id in passage_meta:
                field_value = passage_meta[passage_id].get(field_name)

    # Handle missing fields - they fail all filters except existence checks?
    if field_value is None:
        return False  # or should we treat as false for existence checks?

    operator = next(iter(filter_spec.keys()))
    expected_value = filter_spec[operator]

    return _evaluate_operator(field_value, operator, expected_value)

def _evaluate_operator(field_value: Any, operator: str, expected_value: Any) -> bool:
    """Evaluate a field against an operator and expected value."""
    if operator == "==":
        return field_value == expected_value
    elif operator == "!=":
        return field_value != expected_value
    elif operator == "<":
        return _numeric_compare(field_value, expected_value, lambda a, b: a < b)
    elif operator == "<=":
        return _numeric_compare(field_value, expected_value, lambda a, b: a <= b)
    elif operator == ">":
        return _numeric_compare(field_value, expected_value, lambda a, b: a > b)
    elif operator == ">=":
        return _numeric_compare(field_value, expected_value, lambda a, b: a >= b)
    elif operator == "in":
        if not isinstance(field_value, (list, tuple, set)):
            # Coerce to list if not a sequence
            try:
                field_value = [field_value]
            except:
                return False
        return field_value in expected_value
    elif operator == "not_in":
        if not isinstance(field_value, (list, tuple, set)):
            try:
                field_value = [field_value]
            except:
                return True  # If can't iterate, then not_in is true
        return field_value not in expected_value
    else:
        raise ValueError(f"Unsupported operator: {operator}")

def _numeric_compare(a: Any, b: Any, compare_func) -> bool:
    """Helper for numeric comparisons with type coercion."""
    try:
        a_num = _to_number(a)
        b_num = _to_number(b)
        return compare_func(a_num, b_num)
    except (ValueError, TypeError):
        return False

def _to_number(value: Any) -> float:
    """Convert value to number (int/float)."""
    if isinstance(value, (int, float)):
        return float(value)
    elif isinstance(value, str):
        # Try to parse numbers from string
        try:
            return float(value)
        except ValueError:
            # Fall back to empty string comparison?
            pass
    return 0.0  # Coerce to zero for non-numeric types
